// // This module implements a 4-register file with 8-bit wide registers. It allows for two sources (src1 and src2) to read data from any of the four registers, while disabling one register (designated by dst) from being written with new data (ip) on a clock edge unless the write enable (we) is inactive. Upon receiving a reset signal (rst), all registers are cleared to zero. The outputs (op1 and op2) reflect the contents of the registers specified by src1 and src2, respectively.
module top_module(
    input [1:0] src1,
    input [1:0] src2,
    input [1:0] dst,
    input [7:0] ip,
    input clk,
    input rst,
    input we,
    output [7:0] op1,
    output [7:0] op2
    );reg [7:0] reg_arr [3:0];

			always @ (posedge clk) begin
			if (rst==1) 
			begin	

						reg_arr[0] = 0;
						reg_arr[1] = 0;
						reg_arr[2] = 0;
						reg_arr[3] = 0;

		end 

		else if (we == 1) begin 

			reg_arr[dst] = ip;

		end

	end

	assign op1 = reg_arr[src1];

	assign op2 = reg_arr[src2];

endmodule
